import { useCallback, useEffect, useState, useMemo } from 'react'

import { Link, Outlet, useLocation } from 'react-router-dom'

import { Add as AddIcon, Delete as DeleteIcon } from '@mui/icons-material'
import {
  Container,
  Typography,
  Box,
  Button,
  Stack,
  Chip,
  CircularProgress,
  Alert,
  Paper,
  Divider,
  IconButton,
} from '@mui/material'

import { getTrainingExecutions, deleteTrainingExecution } from '@/api/trainingExecutions'
import { useAuth } from '@/contexts/AuthContext'
import { formatDuration } from '@/hooks/useTimer'
import { routes } from '@/routes'
import type { TrainingExecutionWithPlan } from '@/types/database'
import { isoToLocalDateKey } from '@/utils/date'
import { renderUnit } from '@/utils/unit-utils'

interface DailyGroup {
  dateKey: string
  dateLabel: string
  executions: TrainingExecutionWithPlan[]
  totalDuration: number
  totalUnits: Map<string, number> // unit_name -> count
}

function groupExecutionsByDay(executions: TrainingExecutionWithPlan[]): DailyGroup[] {
  const groups = new Map<string, DailyGroup>()

  for (const execution of executions) {
    const date = new Date(execution.completed_at)
    const dateKey = isoToLocalDateKey(execution.completed_at)

    if (!groups.has(dateKey)) {
      groups.set(dateKey, {
        dateKey,
        dateLabel: date.toLocaleDateString('ko-KR', {
          year: 'numeric',
          month: 'long',
          day: 'numeric',
          weekday: 'short',
        }),
        executions: [],
        totalDuration: 0,
        totalUnits: new Map(),
      })
    }

    const group = groups.get(dateKey)!
    group.executions.push(execution)
    group.totalDuration += execution.duration_seconds

    const unitName = renderUnit(execution.training_plans.unit_name)
    group.totalUnits.set(unitName, (group.totalUnits.get(unitName) || 0) + execution.unit_count)
  }

  // Sort by date descending
  return Array.from(groups.values()).sort((a, b) => b.dateKey.localeCompare(a.dateKey))
}

export function ExecutionsPage() {
  const location = useLocation()
  const isListView = location.pathname === '/executions' || location.pathname === '/executions/'

  return (
    <Container maxWidth="md" disableGutters>
      <Box sx={{ mt: { xs: 2, sm: 4 }, mb: 4, px: { xs: 1, sm: 2 } }}>
        {isListView && (
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mb: 2 }}>
            <Button
              component={Link}
              to={routes.executions.new.$()}
              variant="contained"
              startIcon={<AddIcon />}
            >
              새 훈련
            </Button>
          </Box>
        )}
        {isListView ? <ExecutionsList /> : <Outlet />}
      </Box>
    </Container>
  )
}

function ExecutionsList() {
  const { user } = useAuth()
  const [executions, setExecutions] = useState<TrainingExecutionWithPlan[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const dailyGroups = useMemo(() => groupExecutionsByDay(executions), [executions])

  const loadExecutions = useCallback(async () => {
    try {
      setLoading(true)
      const data = await getTrainingExecutions(user?.id)
      setExecutions(data)
    } catch (err) {
      setError('훈련 기록을 불러오는데 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setLoading(false)
    }
  }, [user?.id])

  useEffect(() => {
    if (user) {
      loadExecutions()
    }
  }, [user, loadExecutions])

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
        <CircularProgress />
      </Box>
    )
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>
  }

  if (executions.length === 0) {
    return <Alert severity="info">아직 훈련 기록이 없습니다. 훈련을 시작해보세요!</Alert>
  }

  async function handleDelete(id: number) {
    if (!confirm('정말 삭제하시겠습니까?')) return
    try {
      await deleteTrainingExecution(id)
      setExecutions((prev) => prev.filter((e) => e.id !== id))
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err)
      alert('삭제에 실패했습니다.')
    }
  }

  return (
    <Stack spacing={3}>
      {dailyGroups.map((group) => (
        <DailyGroupCard key={group.dateKey} group={group} onDelete={handleDelete} />
      ))}
    </Stack>
  )
}

function DailyGroupCard({
  group,
  onDelete,
}: {
  group: DailyGroup
  onDelete: (id: number) => void
}) {
  const unitsSummary = Array.from(group.totalUnits.entries())
    .map(([unit, count]) => `${count} ${unit}`)
    .join(', ')

  return (
    <Paper elevation={2} sx={{ overflow: 'hidden' }}>
      {/* Daily Summary Header */}
      <Box
        sx={{
          p: 2,
          bgcolor: (theme) => (theme.palette.mode === 'dark' ? 'grey.800' : 'grey.100'),
        }}
      >
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 1 }}>
          <Typography variant="subtitle1" fontWeight="bold" sx={{ minWidth: 0, flex: 1 }}>
            📅 {group.dateLabel}
          </Typography>
          <Chip
            label={`${group.executions.length}건`}
            size="small"
            color="primary"
            sx={{ flexShrink: 0 }}
          />
        </Box>
        <Stack direction="row" sx={{ mt: 1, flexWrap: 'wrap', gap: 1 }}>
          <Typography variant="body2" color="text.secondary">
            총 시간: <strong>{formatDuration(group.totalDuration)}</strong>
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ color: 'divider' }}>·</Typography>
          <Typography variant="body2" color="text.secondary">
            수행량: <strong>{unitsSummary}</strong>
          </Typography>
        </Stack>
      </Box>

      <Divider />

      {/* Execution List */}
      <Stack divider={<Divider />}>
        {group.executions.map((execution) => (
          <ExecutionCard key={execution.id} execution={execution} onDelete={onDelete} />
        ))}
      </Stack>
    </Paper>
  )
}

function ExecutionCard({
  execution,
  onDelete,
}: {
  execution: TrainingExecutionWithPlan
  onDelete: (id: number) => void
}) {
  const plan = execution.training_plans
  // const completedDate = new Date(execution.completed_at)
  // const timeStr = completedDate.toLocaleTimeString('ko-KR', {
  //   hour: '2-digit',
  //   minute: '2-digit',
  // })

  function handleDelete(e: React.MouseEvent) {
    e.preventDefault()
    e.stopPropagation()
    onDelete(execution.id)
  }

  return (
    <Box
      component={Link}
      to={routes.executions.detail.$path({ id: execution.id }, {})}
      sx={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        p: 2,
        textDecoration: 'none',
        color: 'inherit',
        '&:hover': {
          bgcolor: (theme) => (theme.palette.mode === 'dark' ? 'grey.800' : 'grey.50'),
        },
      }}
    >
      <Box sx={{ minWidth: 0, flex: 1 }}>
        <Typography variant="body1" fontWeight="medium" noWrap>
          {plan.name}
        </Typography>
        <Typography variant="caption" color="text.secondary">
          {formatDuration(execution.duration_seconds)}
        </Typography>
      </Box>
      <Stack direction="row" spacing={0.5} alignItems="center" sx={{ flexShrink: 0 }}>
        <Chip
          label={`${execution.unit_count} ${renderUnit(plan.unit_name)}`}
          size="small"
          color="primary"
        />
        <IconButton
          size="medium"
          onClick={handleDelete}
          sx={{
            color: 'text.secondary',
            '&:hover': { color: 'error.main' },
          }}
        >
          <DeleteIcon />
        </IconButton>
      </Stack>
    </Box>
  )
}
